import heapq
import itertools

def hamming_distance(s1, s2):
    if len(s1) != len(s2):
        return float('inf') 
    distance = 0
    for char1, char2 in zip(s1, s2):
        if char1 != char2:
            distance += 1
    return distance

def find_distant_barcodes(barcodes, k=1):
    if not barcodes:
        return []

    max_distance_heap = [] 

    for b1, b2 in itertools.combinations(barcodes, 2):
        dist = hamming_distance(b1, b2)

        if dist == float('inf'): # Skip pairs with different lengths if using Hamming
            continue

        heapq.heappush(max_distance_heap, (dist, b1, b2))

        if len(max_distance_heap) > k:
            heapq.heappop(max_distance_heap)

    results = sorted(max_distance_heap, key=lambda x: x[0], reverse=True)
    return results
